    // Safety harness: initialize — detect arithmetic panics
    #[kani::proof]
    fn verify_initialize() {
        let mut ctx: InitializeCtx = kani::any();
        let data: u64 = kani::any();
        kani::assume(ctx.is_signer);
        let _ = initialize(&mut ctx, data);
        // Kani checks: no arithmetic panic, no assertion failure
    }

