    // Safety harness: deposit — detect arithmetic panics
    #[kani::proof]
    fn verify_deposit() {
        let mut ctx: DepositCtx = kani::any();
        let lamports: u64 = kani::any();
        kani::assume(ctx.is_signer);
        let _ = deposit(&mut ctx, lamports);
        // Kani checks: no arithmetic panic, no assertion failure
    }

    // Supply invariant harness: deposit — state.total_supply must increase by lamports
    #[kani::proof]
    fn verify_deposit_supply() {
        let lamports: u64 = kani::any();
        let mut ctx: DepositCtx = kani::any();
        kani::assume(ctx.is_signer);
        kani::assume(ctx.state.total_supply <= u64::MAX / 2);
        kani::assume(lamports <= u64::MAX / 2);
        let pre_total_supply = ctx.state.total_supply;
        let result = deposit(&mut ctx, lamports);
        if result.is_ok() {
            assert!(
                ctx.state.total_supply == pre_total_supply + lamports,
                "SUPPLY_INVARIANT: total_supply not correctly updated after successful deposit"
            );
        }
    }

